import React, { useState, useEffect, useRef } from 'react';
import {
  MapContainer,
  TileLayer,
  GeoJSON,
  ZoomControl,
  LayersControl,
} from 'react-leaflet';
import 'leaflet/dist/leaflet.css';
import chroma from 'chroma-js';
import Sidebar from './Sidebar.js';

// define possible colour scales
const colorSchemes = {
  'Viridis' : chroma.scale('viridis'),
  'Spectral': chroma.scale('Spectral'),
  'Oranges': chroma.scale('Oranges'),
  'Purple-Orange': chroma.scale(['#f1eef6', '#91003f']),
}

// update the internals of a style object
// (this allows shallow updates of a style to just change the colormap)
function updateStyle( style ) {
  // define function that converts a value to a colour
  style.color_func = colorSchemes[style.selectedScheme]
                    .domain([style.vmin, style.vmax])
                    .classes(style.breaks);

  // define function that does styling for a given feature
  style.style_func = (feature) => ({
    fillColor: style.color_func(feature.properties.attr).hex(),
    weight: 1,
    opacity: 0.5,
    color: style.color_func(feature.properties.attr).hex(),
    dashArray: '1',
    fillOpacity: 0.5,
  });
  return style;
}


function buildStyle(mapAttrs, selectedAttribute, data, symmetric=false, 
                    numClasses=12, scheme='Spectral' ) {

  // push attributes to plotted "attr" property
  // (and while we're at it, compute the min and max)
  let vmax = -Infinity;
  let vmin = Infinity;
  mapAttrs.forEach( (feature) => {
    const attr = feature.properties[ data._lookup[ selectedAttribute ] ];
    feature.properties.attr = attr;
    feature.properties.attr_name = selectedAttribute;
    if (isFinite(attr)){
      vmax = Math.max(vmax, attr);
      vmin = Math.min(vmin, attr);
    }
  });

  // change limits if style should be symmetric
  if (symmetric) {
    vmax = Math.max( Math.abs(vmin), Math.abs(vmax) );
    vmin = -vmax;
  }

  // define breaks
  const breaks = chroma.limits([vmin,vmax], 'e', numClasses);
  
  // return
  return updateStyle( {
    attribute: selectedAttribute,
    selectedScheme: scheme,
    schemes: colorSchemes,
    vmin: vmin,
    vmax: vmax,
    breaks: breaks,
    nclasses: numClasses,
  } );
}

function ImpactMap( { data, setSelectedGID, mapAttrs, setMapAttrs, setVariables, mapKey, setMapKey } ) {
  const { BaseLayer, Overlay } = LayersControl; // get Leaflet stuff
  const [selectedAttribute, setSelectedAttribute] = useState("Shared Value"); // data._featureNames.values().next().value
  const [styleProps, setStyleProps] = useState(null); // style object that describes how to draw a map
  const [remapStyle, setRemapStyle] = useState(false); // if true, keep current styling but update cmapping

  if ( (styleProps===null) & (mapAttrs!==null)){
    const symmetric = data._propertyNames.has(selectedAttribute);
    setStyleProps( buildStyle( mapAttrs, selectedAttribute, data, symmetric) ); // define style
  }
  if (remapStyle) {
    // decide if style should be symmetric based on attribute
    const symmetric = data._propertyNames.has(selectedAttribute);
    setStyleProps( buildStyle( mapAttrs, selectedAttribute, data, symmetric,
      styleProps.numClasses, styleProps.selectedScheme ) );
    setMapKey( mapKey + 1 ); // trigger a redraw of the map
    setRemapStyle(false);
  }

  // define callback that allow changing style
  const change_cmap = (event) => {
    const new_style = {...styleProps};
    new_style.selectedScheme = event.target.value;
    setStyleProps( updateStyle(new_style) );
    setMapKey( mapKey + 1 ); // trigger a redraw of the map
  };

  // define callback that allows changing variable(s)
  const update_variables = (new_vars) => {
    setVariables(new_vars); // pass on upwards
    setMapAttrs(null); // trigger a recompute

    // update style
    setRemapStyle(true); // trigger a recompute of the style
  }

  // define callback that allow changing attribute
  const change_attr = (event) => {
    // udpate attribute
    setSelectedAttribute(event.target.value);

    // update style
    setRemapStyle(true); // trigger a recompute of the style
  };

  const onEachFeature = (feature, layer) => {
    layer.bindPopup(
      `[<i>${feature.properties.LVL2}</i>] <b>${feature.properties.attr_name}</b>: ${
        feature.properties.attr !== undefined
          ? (100*feature.properties.attr).toFixed(2)
          : 'N/A'
      }`
    );

    // Event listener for popup open
    layer.on('popupopen', () => {
      //console.log(feature.properties);
      setSelectedGID(feature.properties.index); // set this as the selected feature
    });

    // Event listener for popup close
    layer.on('popupclose', () => {
      //setSelectedGID(null); // set this as the selected feature
    });
  };

  let chloropleth = <></>
  if ((styleProps!==null) & (mapAttrs!==null)){
      // todo; build chloropleth map
      chloropleth = (
        <Overlay checked name="Choropleth">
        <GeoJSON
            key={mapKey} // key that triggers a redraw if style changes
            data={mapAttrs} // actual data frame
            style={styleProps.style_func} // function that does styling
            onEachFeature={onEachFeature}
        />
        </Overlay> );
  }
  
  return( 
    <div style={{ position: 'relative' }}>
          <MapContainer
            center={[50, 15]} // lat lon of initial center
            zoom={5} // initial zoom level
            zoomControl={false}
            style={{ height: 'min(750px,80vh)', width: '100%' }} >
            <ZoomControl position="topright"/>

            <LayersControl position="topright">
            
            {/* Base Layers */}
            <BaseLayer checked name="CartoDB Positron">
              <TileLayer
                attribution='&copy; OpenStreetMap contributors & CartoDB'
                url="https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png"
              />
            </BaseLayer>

            {/* Overlay Layers */
              chloropleth }
            
            {/* Sidebar */}
            <Sidebar styleProps={styleProps} change_cmap={change_cmap}
                    attributes={{
                      "Impacts" : data._propertyNames, // these are visualised as impacts
                      "Indices" : data._featureNames, // these are visualised as spatial indices
                    }} 
                    change_attr={change_attr}
                    selectedAttribute={selectedAttribute}
                    variables={data._variableNames}
                    update_variables={update_variables}
                    data={data}
                    />

          </LayersControl>
      </MapContainer>
      
      {/* Overlay displaying the selected attribute */}
      <div
          style={{
            position: 'absolute',
            textAlign: 'left',
            top: '10px',
            left: '10px',
            padding: '5px 10px',
            backgroundColor: 'rgba(255, 255, 255, 0.8)',
            borderRadius: '4px',
            boxShadow: '0 2px 5px rgba(0, 0, 0, 0.3)',
            fontSize: '14px',
            fontWeight: 'bold',
            zIndex: 1000, // Ensures overlay is above the map
          }}
        >
          <a href={data[data._lookup[selectedAttribute]].source} target="_blank" style={{ color: 'black' }}>
            {selectedAttribute}
          </a>
          <p><i>{data[data._lookup[selectedAttribute]].shortDescription}</i></p>
        </div>
      </div>
  );
}

export default ImpactMap;
