function formatEquation(source, target, obj) {
  if (!obj || !obj.tend || !Array.isArray(obj.tend)) {
      throw new Error("Invalid input: object must have a 'tend' property with an array value.");
  }

  const eq = obj.tend.map(inner => {
      if (Array.isArray(inner)) {
          // Inner list variables are multiplied
          return inner
              .map(item => 
                  typeof item === "string" 
                      ? item.replace(/\//g, ":") 
                      : item.toString().replace(/\//g, ":") 
              )
              .join("×");
      } else {
          // Single variables (outer list) are summed
          return typeof inner === "string" 
              ? inner.replace(/\//g, ":") 
              : inner.toString().replace(/\//g, ":") ;
      }
  }).join(" + ");

  return `∂${source.toString().split("/").pop()}/∂${target.toString().split("/").pop()}=${eq}`;
}
function ImpactGraph({ impactPaths, data, G }) {
  const d3Container = useRef();

  // State for node positions
  /*const [nodePositions, setNodePositions] = useState({
    "properties/Mining":{"x":0.05,"y":0.5},
    "properties/SharedValue":{"x":0.9,"y":0.5},
  });*/
  const [nodePositions, setNodePositions] = useState(default_positions);

  const createGraph = () => {

    // get dims
    const width = window.innerWidth * 0.95;
    const height = 600;

    // Clear the container
    d3.select(d3Container.current).selectAll("*").remove();

    // Prepare data
    const paths = [...impactPaths.positive, ...impactPaths.negative];
    const nodesSet = new Set();
    const links = [];
    //console.log(paths[0].path);
    paths.forEach((item) => {
      item.path.forEach(([source, target, weight, tendency]) => {
        if (tendency){ // following nodes
          nodesSet.add(source);
          nodesSet.add(target);
          links.push({
            source,
            target,
            weight,
            tendency:tendency*weight,
            equation:formatEquation(source, target, G.edges[source][target]),
            logic:G.edges[source][target].logic,
            color: tendency*weight < 0 ? "red" : "blue",
          });
        } else { // first nodes
          nodesSet.add(source);
          nodesSet.add(target);
          links.push({
            source,
            target,
            weight,
            tendency:weight,
            equation:formatEquation(source,target,G.edges[source][target]),
            logic:G.edges[source][target].logic,
            color: weight < 0 ? "red" : "blue",
          });
        }
      });
    });

    const nodes = Array.from(nodesSet).map((id) => ({
      id,
      fx: Object.hasOwn(nodePositions, id) ? nodePositions[id].x * width: null, // persisted node positions
      fy: Object.hasOwn(nodePositions, id) ? nodePositions[id].y * height: null, // persisted node positions
    }));

    // Scale for line width
    const lineWidthScale = d3
      .scaleLinear()
      .domain(d3.extent(links.map((link) => Math.sqrt(Math.abs(link.tendency)))))
      .range([1, 6]); // Line width range

    // Create SVG
    const svg = d3
      .select(d3Container.current)
      .append("svg")
      .attr("width", width)
      .attr("height", height)
      .style("border", "1px solid black");

    // Add title
    svg
      .append("text")
      .attr("x", 20)
      .attr("y", 30)
      .attr("font-size", "20px")
      .attr("font-weight", "bold")
      .attr("fill", "black")
      .text("Impact graph and edge tendencies");

    // Add justification text to the lower-left corner of the SVG
    const justificationText = svg
        .append("text")
        .attr("class", "justification-text")
        .attr("x", 20) // Padding from the left edge
        .attr("y", height - 20) // Position near the bottom
        .attr("font-size", "16px")
        .attr("font-style", "italic")
        .attr("fill", "green")
        .text("Hover the mouse over an edge to see further details."); // Start with no text

    // Define arrow markers
    const markerContainer = svg.append("defs");
    links.forEach((link) => {
      markerContainer
        .append("marker")
        .attr("id", `arrowhead-${link.color}`)
        .attr("viewBox", "0 -5 10 10")
        .attr("refX", 10)
        .attr("refY", 0)
        .attr("markerWidth", 6)
        .attr("markerHeight", 6)
        .attr("orient", "auto")
        .append("path")
        .attr("d", "M0,-5L10,0L0,5")
        .attr("fill", link.color);
    });

    // Create simulation
    const simulation = d3
      .forceSimulation(nodes)
      .force(
        "link",
        d3.forceLink(links).id((d) => d.id).distance(10).strength(0.1)
      )
      .force("collide", d3.forceCollide(60))
      .force("radial", d3.forceRadial(height / 2, width / 2, height / 2).strength(0.4))
      .on("tick", ticked);

    // Draw links
    const link = svg
      .selectAll(".link")
      .data(links)
      .enter()
      .append("line")
      .attr("class", "link")
      .attr("stroke-width", (d) => lineWidthScale(Math.sqrt(Math.abs(d.tendency))))
      .attr("stroke", (d) => d.color)
      .attr("marker-end", (d) => `url(#arrowhead-${d.color})`);

    // Draw nodes
    const node = svg
      .selectAll(".node")
      .data(nodes)
      .enter()
      .append("circle")
      .attr("class", "node")
      .attr("r", 8)
      .attr("fill", "gray")
      .on("dblclick", (event, d) => {
        // Remove fixed position
        const updatedPositions = { ...nodePositions };
        delete updatedPositions[d.id];
        setNodePositions(updatedPositions);

        // Remove fx and fy to free the node
        d.fx = null;
        d.fy = null;

        // Restart simulation to reflect changes
        simulation.alpha(1).restart();
      });

    // Add node labels
    const labels = svg
      .selectAll(".label")
      .data(nodes)
      .enter()
      .append("text")
      .attr("class", "label")
      .attr("font-size", "12px")
      .attr("font-weight", "bold")
      .attr("fill", "black")
      .attr("stroke", "white")
      .attr("stroke-width", 5)
      .attr("paint-order", "stroke")
      .text((d) => data[d.id].name);

    // Add edge labels
    // Add edge labels with hover interaction
    const linkLabels = svg
      .selectAll(".link-label")
      .data(links)
      .enter()
      .append("text")
      .attr("class", "link-label")
      .attr("font-size", "14px")
      .attr("fill", "black")
      .attr("stroke", "white")
      .attr("stroke-width", 5)
      .attr("paint-order", "stroke")
      .text((d) => `${d.weight.toFixed(2)}`)
      .on("mouseover", function (event, d) {
        d3.select(this).text(`${d.equation}`); // Update text to display equation
        d3.select(this).attr("stroke-width", 15);
        d3.select(this).attr("fill", "green");
        d3.select(this).attr("font-size", "20px");
        d3.select(this).attr("font-weight", "bold"); // Make text bold
        justificationText.text(`Justification: ${d.logic}`);
      })
      .on("mouseout", function (event, d) {
        d3.select(this).text(`${d.weight.toFixed(2)}`); // Restore original weight text
        d3.select(this).attr("stroke-width", 5);
        d3.select(this).attr("fill", "black");
        d3.select(this).attr("font-size", "14px");
        d3.select(this).attr("font-weight", "normal"); // Revert text weight to normal
        justificationText.text("Hover the mouse over an edge to see further details.");
      });

    // Update positions on simulation tick
    function ticked() {
      link
        .attr("x1", (d) => d.source.x)
        .attr("y1", (d) => d.source.y)
        .attr("x2", (d) => d.target.x)
        .attr("y2", (d) => d.target.y);
    
      node.attr("cx", (d) => d.x).attr("cy", (d) => d.y);
    
      labels
        .attr("x", (d) => d.x + 10)
        .attr("y", (d) => d.y + 3);
    
      linkLabels
        .attr("x", (d) => (d.source.x + d.target.x) / 2)
        .attr("y", (d) => (d.source.y + d.target.y) / 2)
        .attr("text-anchor", "middle") // Center-align the text horizontally
        .attr("alignment-baseline", "middle"); // Center-align the text vertically
    }

    // Drag behavior
    const drag = d3
      .drag()
      .on("start", (event, d) => {
        if (!event.active) simulation.alphaTarget(0.3).restart();
        d.fx = d.x;
        d.fy = d.y;
      })
      .on("drag", (event, d) => {
        d.fx = event.x;
        d.fy = event.y;
      })
      .on("end", (event, d) => {
        if (!event.active) simulation.alphaTarget(0);

        // Persist the position to nodePositions
        setNodePositions((prevPositions) => ({
          ...prevPositions,
          [d.id]: { x: d.x / width, y: d.y / height},
        }));
      });

    node.call(drag);
  };

  useEffect(() => {
    createGraph();
  }, [impactPaths]);

  return <>
          <div ref={d3Container}></div>
         </>;
}

export default ImpactGraph;
